/**
 * Documentation Routes
 * 
 * Auto-generated documentation API endpoints for the ProjectWorkflow component.
 * These endpoints provide real-time information about:
 * - Database tables and schemas
 * - API routes and endpoints
 * - Data flows and relationships
 * - Module implementation status
 * 
 * All data is dynamically generated by introspecting the actual system.
 * 
 * @created 2026-01-30
 */

const express = require('express');
const router = express.Router();
const DocumentationService = require('../services/DocumentationService');
const logger = require('../utils/logger');

/**
 * GET /api/documentation/overview
 * Get complete system overview including tables, routes, and data flows
 */
router.get('/overview', async (req, res) => {
  try {
    const overview = await DocumentationService.getSystemOverview();
    res.json(overview);
  } catch (error) {
    logger.error('Error getting system overview:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to get system overview',
      message: error.message
    });
  }
});

/**
 * GET /api/documentation/tables
 * Get all database tables with row counts and categories
 */
router.get('/tables', async (req, res) => {
  try {
    const tables = await DocumentationService.getDatabaseTables();
    res.json(tables);
  } catch (error) {
    logger.error('Error getting database tables:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to get database tables',
      message: error.message
    });
  }
});

/**
 * GET /api/documentation/tables/:tableName
 * Get detailed schema for a specific table
 */
router.get('/tables/:tableName', async (req, res) => {
  try {
    const { tableName } = req.params;
    const schema = await DocumentationService.getTableSchema(tableName);
    res.json(schema);
  } catch (error) {
    logger.error(`Error getting schema for table ${req.params.tableName}:`, error);
    res.status(500).json({
      success: false,
      error: 'Failed to get table schema',
      message: error.message
    });
  }
});

