/**
 * GET /api/documentation/health
 * Health check for documentation service
 */
router.get('/health', (req, res) => {
  res.json({
    success: true,
    service: 'DocumentationService',
    status: 'healthy',
    timestamp: new Date().toISOString()
  });
});

module.exports = router;
